# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

from flask import Flask, request, jsonify
import redis

app = Flask(__name__)
cluster = redis.StrictRedis(connection_class=redis.ClusterIORedis)

# Connect to the Redis cluster. This should ideally be done outside of any function call.
# Replace the node names and password with your actual Redis cluster details.
cluster.connect()

def set_key(key, value, ttl):
    return cluster.set(key, value, ex=ttl)

def get_key(key):
    return cluster.get(key)

def delete_key(key):
    return cluster.delete(key)

@app.route('/session/store', methods=['POST'])
def store_session():
    data = request.get_json()
    key = data['session_id']
    value = jsonify(data)
    ttl = 60 * 60 * 24 * 7 # TTL is set to 1 week in this example

    if not set_key(key, value, ttl):
        return "Error storing session", 500

    return "Session stored successfully", 200

@app.route('/api_key/store', methods=['POST'])
def store_api_key():
    data = request.get_json()
    key = data['api_key']
    value = jsonify(data)
    ttl = 60 * 60 * 24 * 30 # TTL is set to 1 month in this example

    if not set_key(key, value, ttl):
        return "Error storing api key", 500

    return "Api key stored successfully", 200

if __name__ == "__main__":
    app.run(debug=True)